<?php
namespace App\Jobs;use App\Models\{DailyReport,MissingDailyReport,Workspace};use Illuminate\Bus\Queueable;use Illuminate\Contracts\Queue\ShouldQueue;use Illuminate\Foundation\Bus\Dispatchable;use Illuminate\Queue\InteractsWithQueue;use Illuminate\Queue\SerializesModels;
class DetectMissingDailyReportsJob implements ShouldQueue{use Dispatchable,InteractsWithQueue,Queueable,SerializesModels;public function handle():void{Workspace::query()->where('status','active')->with('settings','users')->chunkById(50,function($workspaces){foreach($workspaces as $w){$s=$w->settings;if(!$s?->daily_report_required)continue;$tz=$s->timezone?:config('app.timezone');$now=now($tz);$date=$now->toDateString();$days=$s->working_days?:['monday','tuesday','wednesday','thursday','friday'];if(!in_array(strtolower($now->englishDayOfWeek),array_map('strtolower',$days),true))continue;$deadline=$now->copy()->setTimeFromTimeString($s->daily_report_deadline?:'23:59:59');if($now->lessThan($deadline))continue;foreach($w->users()->wherePivot('status','active')->get() as $u){$exists=DailyReport::withoutWorkspaceScope()->where('workspace_id',$w->id)->where('user_id',$u->id)->whereDate('report_date',$date)->whereIn('status',['submitted','reviewed','approved'])->exists();if(!$exists)MissingDailyReport::withoutWorkspaceScope()->firstOrCreate(['workspace_id'=>$w->id,'user_id'=>$u->id,'report_date'=>$date],['expected_deadline'=>$deadline->utc(),'status'=>'missing','marked_at'=>now()]);}}});}}
